import React from "react";
import FeatureDetail from "./FeatureDetail";

const pageData = {
  title: "Zero-Trust Architecture",
  subtitle: "Never trust, always verify - every request authenticated and continuously validated",
  description: "Implement a comprehensive Zero-Trust security model that verifies every request, regardless of origin. Our platform provides micro-segmentation, just-in-time access, and continuous verification throughout the entire session lifecycle. Zero Trust assumes breach and verifies every request as if it originates from an untrusted network.",
  benefits: [
    "Never trust, always verify approach for all resources",
    "Micro-segmentation with software-defined perimeters",
    "Just-in-Time (JIT) and Just-Enough-Access (JEA)",
    "Continuous verification throughout session lifecycle",
    "Real-time Behavioral Biometrics for identity confirmation"
  ],
  features: [
    { title: "Identity Verification", description: "Multi-factor authentication with risk-based adaptive policies" },
    { title: "Micro-Segmentation", description: "Fine-grained network segmentation to limit lateral movement" },
    { title: "Device Trust", description: "Continuous assessment of device health and compliance status" },
    { title: "Session Monitoring", description: "Real-time session analysis with anomaly detection" },
    { title: "Policy Engine", description: "Centralized policy management with dynamic enforcement" }
  ],
  howItWorks: [
    { title: "Identity Assessment", description: "Verify user identity using multiple authentication factors" },
    { title: "Device Evaluation", description: "Check device compliance and security posture" },
    { title: "Context Analysis", description: "Evaluate request context including location, time, and behavior" },
    { title: "Continuous Validation", description: "Ongoing verification throughout the entire session" }
  ],
  color: "#06b6d4",
  icon: "M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z",
  gradient: "from-cyan-500 to-blue-500"
};

function ZeroTrust() {
  return <FeatureDetail {...pageData} />;
}

export default ZeroTrust;
